<?php
/** Cross-cutting production guards loaded after Stonefellow configuration. */
function sf_runtime_guard_pdo(): ?PDO { static $pdo=false;global$database;if($pdo!==false)return$pdo;$host=trim((string)($database['host']??''));$name=trim((string)($database['name']??''));$user=trim((string)($database['user']??''));$pass=(string)($database['pass']??'');$port=(int)($database['port']??3306);if($host===''||$name===''||$user===''||str_contains($host,';')||str_contains($name,';'))return$pdo=null;try{return$pdo=new PDO("mysql:host={$host};port={$port};dbname={$name};charset=utf8mb4",$user,$pass,[PDO::ATTR_ERRMODE=>PDO::ERRMODE_EXCEPTION,PDO::ATTR_DEFAULT_FETCH_MODE=>PDO::FETCH_ASSOC,PDO::ATTR_EMULATE_PREPARES=>false]);}catch(Throwable$e){return$pdo=null;} }
function sf_runtime_guard_user_id(): int { foreach(['sf_user_id','user_id','member_id']as$key)if(isset($_SESSION[$key])&&filter_var($_SESSION[$key],FILTER_VALIDATE_INT,['options'=>['min_range'=>1]]))return(int)$_SESSION[$key];return 0; }
function sf_runtime_guard_abort(int $status,string $message): never { http_response_code($status);header('Cache-Control: no-store, private');header('Content-Type: text/plain; charset=utf-8');echo$message."\nRequest ID: ".sf_security_request_id();exit; }
function sf_runtime_guard_remember_cookie(): void { if(sf_runtime_guard_user_id()>0||empty($_COOKIE['sf_remember']))return;$parts=explode(':',(string)$_COOKIE['sf_remember'],2);if(count($parts)!==2||!preg_match('/^[a-f0-9]{32}$/i',$parts[0])||!preg_match('/^[a-f0-9]{64}$/i',$parts[1]))return;[$selector,$validator]=$parts;$pdo=sf_runtime_guard_pdo();if(!$pdo)return;try{$stmt=$pdo->prepare("SELECT t.id,t.user_id,t.token_hash,u.status FROM user_auth_tokens t JOIN users u ON u.id=t.user_id WHERE t.selector=? AND t.token_type='remember_me' AND t.used_at IS NULL AND t.expires_at>NOW() LIMIT 1");$stmt->execute([$selector]);$row=$stmt->fetch();if(!$row||($row['status']??'')!=='active'||!hash_equals((string)$row['token_hash'],hash('sha256',$validator)))return;$newSelector=bin2hex(random_bytes(16));$newValidator=bin2hex(random_bytes(32));$expires=time()+2592000;$pdo->beginTransaction();$pdo->prepare('UPDATE user_auth_tokens SET used_at=NOW() WHERE id=? AND used_at IS NULL')->execute([(int)$row['id']]);$pdo->prepare("INSERT INTO user_auth_tokens (user_id,selector,token_hash,token_type,expires_at) VALUES (?,?,?,'remember_me',?)")->execute([(int)$row['user_id'],$newSelector,hash('sha256',$newValidator),date('Y-m-d H:i:s',$expires)]);$pdo->commit();session_regenerate_id(true);$_SESSION['sf_user_id']=(int)$row['user_id'];$_SESSION['sf_login_at']=time();setcookie('sf_remember',$newSelector.':'.$newValidator,['expires'=>$expires,'path'=>sf_security_cookie_path(),'secure'=>sf_is_https(),'httponly'=>true,'samesite'=>'Lax']);}catch(Throwable$e){if($pdo->inTransaction())$pdo->rollBack();} }
function sf_runtime_guard_table_exists(PDO $pdo,string $table): bool { try{$stmt=$pdo->prepare('SHOW TABLES LIKE ?');$stmt->execute([$table]);return(bool)$stmt->fetchColumn();}catch(Throwable$e){return false;} }
function sf_runtime_guard_ai_permission(string $script): string { $base=basename($script);if($base==='ai-settings.php')return'admin.settings.manage';if($base==='ai-autonomy-policies.php')return'admin.security.manage';if(preg_match('/^ai-(platform|execution|publishing|operations|mission)/',$base))return'admin.ops.manage';if(preg_match('/^ai-(script|media)/',$base)||in_array($base,['theme-images.php','storyboard-builder.php'],true))return'admin.content.manage';return''; }
function sf_runtime_guard_require_permission(PDO $pdo,int $userId,string $permission): void { if($permission===''||!sf_runtime_guard_table_exists($pdo,'admin_user_roles')||!sf_runtime_guard_table_exists($pdo,'admin_role_permissions')||!sf_runtime_guard_table_exists($pdo,'admin_roles'))return;try{$assigned=$pdo->prepare('SELECT COUNT(*) FROM admin_user_roles WHERE user_id=?');$assigned->execute([$userId]);if((int)$assigned->fetchColumn()===0)return;$stmt=$pdo->prepare("SELECT COUNT(*) FROM admin_user_roles ur INNER JOIN admin_role_permissions rp ON rp.role_id=ur.role_id INNER JOIN admin_roles r ON r.id=ur.role_id WHERE ur.user_id=? AND rp.permission_key=? AND r.status='active'");$stmt->execute([$userId,$permission]);if((int)$stmt->fetchColumn()===0)sf_runtime_guard_abort(403,'Your admin role does not permit this AI module.');}catch(Throwable$e){sf_runtime_guard_abort(503,'Admin permission verification is unavailable.');} }
function sf_runtime_guard_admin(): void { $script=str_replace('\\','/',(string)($_SERVER['SCRIPT_NAME']??''));if(!preg_match('~/admin/[^/]+\.php$~i',$script))return;$pdo=sf_runtime_guard_pdo();if(!$pdo){if(!sf_is_production()&&sf_env_bool('SF_ALLOW_ADMIN_PREVIEW',false))return;sf_runtime_guard_abort(503,'Admin access is unavailable until the database is configured.');}$userId=sf_runtime_guard_user_id();if($userId<=0){header('Location: '.sf_url('signin.php'),true,302);exit;}$stmt=$pdo->prepare('SELECT role,status FROM users WHERE id=? LIMIT 1');$stmt->execute([$userId]);$user=$stmt->fetch();if(!$user||($user['status']??'')!=='active'||($user['role']??'')!=='admin')sf_runtime_guard_abort(403,'Administrator permission is required.');sf_runtime_guard_require_permission($pdo,$userId,sf_runtime_guard_ai_permission($script));if(($_SERVER['REQUEST_METHOD']??'GET')==='POST'){$provided=(string)($_POST['csrf_token']??'');$expected=(string)($_SESSION['sf_csrf_token']??'');if($provided===''||$expected===''||!hash_equals($expected,$provided))sf_runtime_guard_abort(419,'The admin security token is invalid or expired.');} }
function sf_runtime_guard_public_auth(): void { if(PHP_SAPI==='cli'||($_SERVER['REQUEST_METHOD']??'GET')!=='POST')return;$page=basename((string)($_SERVER['SCRIPT_NAME']??''));if(in_array($page,['signup.php','reset-password.php'],true)){$password=(string)($_POST['password']??$_POST['new_password']??'');$minimum=sf_is_production()?12:8;if($password!==''&&strlen($password)<$minimum)sf_runtime_guard_abort(422,"Passwords must contain at least {$minimum} characters.");}if($page==='signin.php'){$email=strtolower(trim((string)($_POST['email']??'')));$limit=sf_security_session_rate_limit('signin|'.$email.'|'.($_SERVER['REMOTE_ADDR']??''),20,900);if(!$limit['allowed'])sf_runtime_guard_abort(429,'Too many sign-in attempts.');}if($page==='billing-checkout.php'&&(string)($_POST['action']??'')==='complete'&&sf_is_production()&&!sf_env_bool('SF_ALLOW_SANDBOX_SUBSCRIPTIONS',false))sf_runtime_guard_abort(403,'Local sandbox membership activation is disabled in production.');if($page==='checkout.php'&&sf_is_production()&&!sf_env_bool('SF_ALLOW_SANDBOX_MERCH',false))sf_runtime_guard_abort(403,'Local sandbox merch checkout is disabled in production.'); }
sf_runtime_guard_remember_cookie();sf_runtime_guard_public_auth();sf_runtime_guard_admin();
